const query = ($json.query || '').trim();
const queryLower = query.toLowerCase();
const telefone = ($json.telefone || '').replace('@s.whatsapp.net', '');

let action = 'consultar';
let categoria = '';
let monto_limite = 0;
let mes_anio = '';

// Detecta ação
if (queryLower.includes('definir') || queryLower.includes('establecer') || queryLower.includes('crear') || queryLower.includes('set') || queryLower.includes('poner')) {
  action = 'definir';
} else if (queryLower.includes('eliminar') || queryLower.includes('borrar') || queryLower.includes('quitar') || queryLower.includes('delete')) {
  action = 'eliminar';
} else if (queryLower.includes('editar') || queryLower.includes('cambiar') || queryLower.includes('actualizar') || queryLower.includes('modificar')) {
  action = 'editar';
}

// Extrai monto
const montoMatch = query.match(/(\d[\d.,]+)/);
if (montoMatch) {
  monto_limite = Number(montoMatch[1].replace(/\./g, '').replace(',', '.'));
}

// Extrai mes_anio (formato YYYY-MM)
const mesMatch = query.match(/(\d{4}-\d{2})/);
if (mesMatch) {
  mes_anio = mesMatch[1];
}

// Extrai categoria - remove palavras de ação
const removeWords = ['definir','establecer','crear','set','poner','eliminar','borrar','quitar','delete','editar','cambiar','actualizar','modificar','consultar','ver','presupuesto','presupuestos','para','de','la','el','un','una','en','con','por','favor','puede','puedes','monto','limite','límite'];
let cleanCat = query;
// Remove o monto do texto
if (montoMatch) cleanCat = cleanCat.replace(montoMatch[0], '');
if (mesMatch) cleanCat = cleanCat.replace(mesMatch[0], '');
removeWords.forEach(w => {
  cleanCat = cleanCat.replace(new RegExp('\\b' + w + '\\b', 'gi'), '');
});
categoria = cleanCat.replace(/[?!.,;:$]/g, '').trim();

// Capitalizar primeira letra
if (categoria) categoria = categoria.charAt(0).toUpperCase() + categoria.slice(1);

return [{ json: { action, categoria, monto_limite, mes_anio, telefone, originalQuery: query } }];

const resposta = $input.first().json;
const parsed = $node['Parsear Query'].json;

if (resposta.success) {
  if (parsed.action === 'consultar') {
    if (!resposta.presupuestos || resposta.presupuestos.length === 0) {
      return [{ json: { mensagem: '💰 *Presupuestos:*\n\nNo tienes presupuestos definidos para este periodo.' } }];
    }
    const lista = resposta.presupuestos.map(p =>
      `• *${p.categoria}*: ${p.gastado} / ${p.limite} (${p.porcentaje}) ${p.alerta}`
    ).join('\n');
    return [{ json: { mensagem: `💰 *Estado de Presupuestos (${resposta.periodo}):*\n\n${lista}` } }];
  }
  return [{ json: { mensagem: resposta.message || '✅ Presupuesto actualizado.' } }];
}

return [{ json: { mensagem: `❌ Error: ${resposta.error || 'Error desconocido'}` } }];
